const LOGO_B64 = "data:image/png;base64,";

const SanabicLogo = ({ size = 40, showText = true, dark = false }) => (
  <img
    src={LOGO_B64}
    alt="Sanabic Logo"
    style={{
      width:  size * 2.4,
      height: "auto",
      objectFit: "contain",
      // invert to white when on dark navbar bg
      filter: dark ? "brightness(0) invert(1)" : "none",
      display: "block",
    }}
  />
);

