const StatusBadge = ({ status }) => {
  const s = STATUS_CFG[status] || { label: status, color: C.gray, bg: C.border };
  return <span style={{ background: s.bg, color: s.color, padding:"3px 10px", borderRadius:99, fontSize:12, fontWeight:700, whiteSpace:"nowrap", border:`1px solid ${s.color}44` }}>{s.dot} {s.label}</span>;
};

const Stat = ({ icon, label, value, color, sub }) => (
  <div style={{ background:C.bgCard, border:`1px solid ${C.border}`, borderRadius:12, padding:"16px 18px", display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
    <div>
      <div style={{ color:C.gray, fontSize:12, marginBottom:6 }}>{label}</div>
      <div style={{ color: color||C.gold, fontWeight:800, fontSize:26, lineHeight:1 }}>{value}</div>
      {sub && <div style={{ color:C.gray, fontSize:11, marginTop:5 }}>{sub}</div>}
    </div>
    <div style={{ fontSize:28 }}>{icon}</div>
  </div>
);

const Btn = ({ children, onClick, color=C.gold, textColor=C.bg, outline, full, sm, icon, disabled }) => (
  <button onClick={onClick} disabled={disabled} style={{
    display:"flex", alignItems:"center", justifyContent:"center", gap:6,
    width: full ? "100%" : undefined,
    padding: sm ? "7px 14px" : "11px 20px",
    fontSize: sm ? 13 : 14, fontWeight:700,
    background: outline ? "transparent" : disabled ? C.border : color,
    color: outline ? color : textColor,
    border: `2px solid ${disabled ? C.border : color}`,
    borderRadius:9, cursor: disabled ? "not-allowed" : "pointer",
    opacity: disabled ? 0.6 : 1, transition:"opacity .15s", fontFamily:"inherit",
  }}>{icon && <span>{icon}</span>}{children}</button>
);

const Input = ({ label, value, onChange, type="text", placeholder, rows, options, required, hint }) => (
  <div style={{ marginBottom:14 }}>
    {label && <div style={{ color:C.gray, fontSize:13, marginBottom:5 }}>{label}{required && <span style={{color:C.red}}> *</span>}</div>}
    {hint && <div style={{ color:C.gray, fontSize:11, marginBottom:4 }}>{hint}</div>}
    {options ? (
      <select value={value} onChange={e=>onChange(e.target.value)}
        style={{ width:"100%", padding:"11px 13px", background:C.bgMid, border:`1px solid ${C.border}`, borderRadius:9, color:C.white, fontSize:14, boxSizing:"border-box" }}>
        {options.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}
      </select>
    ) : rows ? (
      <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={rows}
        style={{ width:"100%", padding:"11px 13px", background:C.bgMid, border:`1px solid ${C.border}`, borderRadius:9, color:C.white, fontSize:14, resize:"vertical", boxSizing:"border-box", fontFamily:"inherit" }}/>
    ) : (
      <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{ width:"100%", padding:"11px 13px", background:C.bgMid, border:`1px solid ${C.border}`, borderRadius:9, color:C.white, fontSize:14, boxSizing:"border-box" }}/>
    )}
  </div>
);

const Modal = ({ title, onClose, children, accent }) => (
  <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.75)", display:"flex", alignItems:"flex-end", justifyContent:"center", zIndex:200, padding:"0" }}>
    <div style={{ background:C.bgMid, border:`1px solid ${accent||C.border}`, borderRadius:"16px 16px 0 0", width:"100%", maxWidth:520, maxHeight:"90vh", overflow:"auto" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"16px 18px", borderBottom:`1px solid ${C.border}`, position:"sticky", top:0, background:C.bgMid, zIndex:1 }}>
        <div style={{ color: accent||C.gold, fontWeight:700, fontSize:16 }}>{title}</div>
        <button onClick={onClose} style={{ background:C.border, border:"none", color:C.white, borderRadius:8, width:32, height:32, cursor:"pointer", fontSize:16 }}>×</button>
      </div>
      <div style={{ padding:18 }}>{children}</div>
    </div>
  </div>
);

const Toast = ({ msg, type }) => (
  <div style={{ position:"fixed", bottom:24, left:"50%", transform:"translateX(-50%)", background: type==="error"?C.redDark: type==="warn"?C.orangeDark:"#0a2d16",
    color: type==="error"?C.red: type==="warn"?C.orange:C.green, border:`1px solid ${type==="error"?C.red:type==="warn"?C.orange:C.green}`,
    borderRadius:10, padding:"12px 22px", zIndex:999, fontWeight:600, fontSize:14, display:"flex", alignItems:"center", gap:8, boxShadow:"0 8px 32px #00000088", whiteSpace:"nowrap" }}>
    {type==="error"?"❌":type==="warn"?"⚠️":"✅"} {msg}
  </div>
);

const Divider = () => <div style={{ height:1, background:C.border, margin:"14px 0" }}/>;

const WALog = ({ log }) => (
  <div style={{ background:"#071410", border:`1px solid ${C.wa}33`, borderRadius:12, padding:14, marginTop:14 }}>
    <div style={{ color:C.wa, fontWeight:700, fontSize:13, marginBottom:10 }}>💬 سجل واتساب بزنس</div>
    {log.length===0 ? <div style={{color:C.gray,fontSize:13,textAlign:"center",padding:"10px 0"}}>لا توجد رسائل</div>
    : log.slice(-5).reverse().map(m=>(
      <div key={m.id} style={{ background:"#0d1e10", borderRadius:8, padding:"9px 12px", marginBottom:8, borderRight:`3px solid ${C.wa}` }}>
        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:3 }}>
          <span style={{ color:C.wa, fontWeight:600, fontSize:12 }}>→ {m.name}</span>
          <span style={{ color:C.gray, fontSize:11 }}>{m.time}</span>
        </div>
        <div style={{ color:C.grayLight, fontSize:12, lineHeight:1.5, whiteSpace:"pre-line" }}>{m.message}</div>
      </div>
    ))}
  </div>
);

const Timeline = ({ events }) => (
  <div>
    {events.map((e,i)=>(
      <div key={i} style={{ display:"flex", gap:10, marginBottom:10 }}>
        <div style={{ display:"flex", flexDirection:"column", alignItems:"center", flexShrink:0 }}>
          <div style={{ width:26, height:26, borderRadius:"50%", background:e.done?C.green:C.border, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, color:"#fff", fontWeight:700 }}>{e.done?"✓":"○"}</div>
          {i<events.length-1 && <div style={{ width:2, flex:1, background:C.border, margin:"3px 0" }}/>}
        </div>
        <div style={{ paddingBottom:8 }}>
          <div style={{ color:C.white, fontWeight:600, fontSize:13 }}>{e.step}</div>
          {e.time&&<div style={{ color:C.gray, fontSize:11 }}>{e.time}</div>}
          {e.note&&<div style={{ color:C.grayLight, fontSize:12, marginTop:2 }}>{e.note}</div>}
        </div>
      </div>
    ))}
  </div>
);

// Pipeline steps
const PIPE_STEPS = [{label:"العميل",icon:"👤"},{label:"المندوب",icon:"🧑‍💼"},{label:"الحسابات",icon:"💰"},{label:"الصيانة",icon:"🔧"},{label:"الفاتورة",icon:"🧾"}];
const PIPE_IDX = { pending_agent:0, pending_accounts:1, accounts_approved:2, in_maintenance:3, completed:4, invoiced:4, rejected:1 };
const Pipeline = ({ status }) => {
  const cur = PIPE_IDX[status]??0;
  return (
    <div style={{ display:"flex", alignItems:"flex-start", width:"100%" }}>
      {PIPE_STEPS.map((s,i)=>(
        <div key={i} style={{ display:"flex", alignItems:"center", flex:1 }}>
          <div style={{ display:"flex", flexDirection:"column", alignItems:"center", flex:"0 0 auto" }}>
            <div style={{ width:30, height:30, borderRadius:"50%", fontSize:13, display:"flex", alignItems:"center", justifyContent:"center",
              background:i<cur?C.green:i===cur?BRAND.blue:C.border, border:i===cur?`2px solid ${BRAND.blueLight}`:"none",
              boxShadow:i===cur?`0 0 10px ${BRAND.blue}66`:"none" }}>{i<cur?"✓":s.icon}</div>
            <div style={{ color:i<=cur?C.white:C.gray, fontSize:9, marginTop:3, textAlign:"center", maxWidth:40 }}>{s.label}</div>
          </div>
          {i<PIPE_STEPS.length-1 && <div style={{ flex:1, height:2, background:i<cur?C.green:C.border, margin:"0 2px", marginBottom:16 }}/>}
        </div>
      ))}
    </div>
  );
};

