function Bar({ value, max, color, height=8 }) {
  const pct = max > 0 ? Math.min((value / max) * 100, 100) : 0;
  return (
    <div style={{ background:C.border, borderRadius:99, height, overflow:"hidden" }}>
      <div style={{ width:`${pct}%`, background:color||`linear-gradient(90deg,${C.gold},${C.goldBright})`,
        height:"100%", borderRadius:99, transition:"width .6s ease" }}/>
    </div>
  );
}

function MiniDonut({ segments }) {
  // Simple CSS-based donut using conic-gradient
  const total = segments.reduce((s,x)=>s+x.value,0)||1;
  let pct = 0;
  const gradient = segments.map(s=>{
    const from = pct; pct += (s.value/total)*100;
    return `${s.color} ${from.toFixed(1)}% ${pct.toFixed(1)}%`;
  }).join(", ");
  return (
    <div style={{ position:"relative", width:110, height:110, flexShrink:0 }}>
      <div style={{ width:"100%", height:"100%", borderRadius:"50%",
        background:`conic-gradient(${gradient})` }}/>
      <div style={{ position:"absolute", inset:"18px", borderRadius:"50%", background:C.bgCard,
        display:"flex", alignItems:"center", justifyContent:"center",
        color:C.white, fontWeight:800, fontSize:18 }}>{total}</div>
    </div>
  );
}

